import{_ as a,o as t,c as e,ai as i}from"./chunks/framework.DRzLPsDb.js";const k=JSON.parse('{"title":"What is ra?","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/index.md","filePath":"concepts/index.md"}'),r={name:"concepts/index.md"};function n(o,s,h,l,d,p){return t(),e("div",null,[...s[0]||(s[0]=[i(`<h1 id="what-is-ra" tabindex="-1">What is ra? <a class="header-anchor" href="#what-is-ra" aria-label="Permalink to &quot;What is ra?&quot;">​</a></h1><p>ra is a small, hackable agent. Nothing hidden behind abstractions you can&#39;t reach.</p><p>It doesn&#39;t ship with a system prompt. Every part of the loop is exposed via config and can be extended by writing scripts or plain TypeScript. <a href="/ra/v/0.0.3/middleware/">Middleware hooks</a> let you intercept every step — model calls, tool execution, streaming, all of it.</p><p>It talks to Anthropic, OpenAI, Google, Ollama, Bedrock, and Azure. Switch providers with ease.</p><p>It comes with <a href="/ra/v/0.0.3/tools/">built-in tools</a> for filesystem, shell, network, and user interaction. Connect to MCP servers for additional tools. Persistent <a href="/ra/v/0.0.3/core/sessions.html">sessions</a> via JSONL. An FTS5 <a href="/ra/v/0.0.3/configuration/#memory">memory</a> backed by SQLite.</p><p>It speaks <a href="/ra/v/0.0.3/modes/mcp.html">MCP</a> both ways — use external MCP servers, or expose ra itself as an MCP server so you can use it from Cursor, Claude Desktop, or anything else that speaks the protocol.</p><p>It gives you real control over <a href="/ra/v/0.0.3/core/context-control.html">context</a>. Deterministic discovery for common formats (CLAUDE.md, AGENTS.md, README.md), pattern resolution, prompt caching, compaction, token tracking. A <a href="/ra/v/0.0.3/skills/">skill system</a> that can pull skills from GitHub repos or npm packages.</p><p>Extended thinking for models that support it — watch the model reason in real time.</p><p>It runs as a <a href="/ra/v/0.0.3/modes/cli.html">CLI</a>, <a href="/ra/v/0.0.3/modes/repl.html">REPL</a>, <a href="/ra/v/0.0.3/modes/http.html">HTTP server</a>, or <a href="/ra/v/0.0.3/modes/mcp.html">MCP server</a>. No runtime dependencies.</p><p>Structured logs and traces per session, so you can actually see what your agent is doing.</p><p>All of this is <a href="/ra/v/0.0.3/configuration/">configurable</a> via a layered config system — env vars, config files (JSON, YAML, TOML), or CLI flags. Each layer overrides the last.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ra</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;What is the capital of France?&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ra</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --provider</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openai</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --model</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gpt-4.1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Explain this error&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ra</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --skill</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> code-review</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --file</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> diff.patch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Review this diff&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server.log</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ra</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Find the root cause of these errors&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ra</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # interactive REPL</span></span></code></pre></div><h2 id="the-config-is-the-agent" tabindex="-1">The config is the agent <a class="header-anchor" href="#the-config-is-the-agent" aria-label="Permalink to &quot;The config is the agent&quot;">​</a></h2><p>Drop a <code>ra.config.yml</code> in a repo and that directory becomes a project-specific assistant. Set env vars for a different persona. Pass <code>--skill</code> to inject a role at runtime. Run <code>--mcp-stdio</code> to expose it as a tool for Cursor or Claude Desktop. Same binary, different agent — every time.</p><h2 id="what-s-in-the-box" tabindex="-1">What&#39;s in the box <a class="header-anchor" href="#what-s-in-the-box" aria-label="Permalink to &quot;What&#39;s in the box&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td><a href="/ra/v/0.0.3/core/agent-loop.html">The Agent Loop</a></td><td>Model → tools → repeat, with streaming, middleware hooks at every step, and configurable iteration limits</td></tr><tr><td><a href="/ra/v/0.0.3/core/context-control.html">Context Control</a></td><td>Smart compaction, token tracking, prompt caching, extended thinking, context discovery, pattern resolution</td></tr><tr><td><a href="/ra/v/0.0.3/modes/cli.html">CLI</a></td><td>One-shot prompts, piping, chaining, scriptable</td></tr><tr><td><a href="/ra/v/0.0.3/modes/repl.html">REPL</a></td><td>Interactive sessions with history, slash commands, file attachments</td></tr><tr><td><a href="/ra/v/0.0.3/modes/http.html">HTTP API</a></td><td>Sync and streaming chat, session management</td></tr><tr><td><a href="/ra/v/0.0.3/modes/mcp.html">MCP</a></td><td>Client (pull tools from MCP servers) and server (expose ra as a tool)</td></tr><tr><td><a href="/ra/v/0.0.3/tools/">Built-in Tools</a></td><td>Filesystem, shell, network, and user interaction tools</td></tr><tr><td><a href="/ra/v/0.0.3/skills/">Skills</a></td><td>Reusable instruction bundles — roles, behaviors, scripts, and reference docs</td></tr><tr><td><a href="/ra/v/0.0.3/middleware/">Middleware</a></td><td>Hooks at every loop stage — intercept, modify, or stop the loop</td></tr><tr><td><a href="/ra/v/0.0.3/core/sessions.html">Sessions</a></td><td>Persist conversations as JSONL, resume from any interface, auto-prune</td></tr><tr><td><a href="/ra/v/0.0.3/core/file-attachments.html">File Attachments</a></td><td>Images, PDFs, text files — auto-detected and sent in the right format</td></tr><tr><td><a href="/ra/v/0.0.3/configuration/#memory">Memory</a></td><td>Persistent SQLite memory with FTS — save, search, forget across conversations</td></tr><tr><td><a href="/ra/v/0.0.3/configuration/">Configuration</a></td><td>Layered: defaults → file → env → CLI. The config is the agent</td></tr></tbody></table><h2 id="use-cases" tabindex="-1">Use cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use cases&quot;">​</a></h2><h3 id="ci-caught-a-flaky-test" tabindex="-1">CI caught a flaky test <a class="header-anchor" href="#ci-caught-a-flaky-test" aria-label="Permalink to &quot;CI caught a flaky test&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ra</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --skill</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> debugger</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --file</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test-output.log</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Why is this test failing?&quot;</span></span></code></pre></div><p>Reads the logs, explains the root cause, and exits. Pipe the output to Slack or a PR comment.</p><h3 id="you-re-building-a-feature" tabindex="-1">You&#39;re building a feature <a class="header-anchor" href="#you-re-building-a-feature" aria-label="Permalink to &quot;You&#39;re building a feature&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ra</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">›</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /attach</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/auth.ts</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">›</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> How</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> should</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> I</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rate</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> limiting</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> to</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> this</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> endpoint?</span></span></code></pre></div><p>Attach files, ask follow-ups, keep context. Resume the session tomorrow with <code>/resume</code>.</p><h3 id="your-product-needs-ai" tabindex="-1">Your product needs AI <a class="header-anchor" href="#your-product-needs-ai" aria-label="Permalink to &quot;Your product needs AI&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ra</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --http</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --http-port</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 3000</span></span></code></pre></div><p>POST a message, get SSE chunks back. No framework — just <code>Bun.serve()</code> under the hood.</p><h3 id="your-editor-needs-a-specialist" tabindex="-1">Your editor needs a specialist <a class="header-anchor" href="#your-editor-needs-a-specialist" aria-label="Permalink to &quot;Your editor needs a specialist&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ra</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --mcp-stdio</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --skill</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> code-review</span></span></code></pre></div><p>Now Cursor or Claude Desktop has a dedicated code reviewer that uses your project&#39;s style guide, your skills, your system prompt.</p>`,29)])])}const u=a(r,[["render",n]]);export{k as __pageData,u as default};
